node -e "
const fs = require('fs');
const cfg = JSON.parse(fs.readFileSync(process.env.HOME + '/.openclaw/openclaw.json', 'utf8'));

// 1. tools.profile: full → auto（按需加载工具，提升速度）
// 2. tools.exec.strictInlineEval: true → false（inline-eval 不再单独触发确认）
// 3. tools.exec.security 显式设为 'allow'（最宽松的 exec 安全模式）
if (!cfg.tools) cfg.tools = {};
if (!cfg.tools.exec) cfg.tools.exec = {};

cfg.tools.profile = 'auto';
cfg.tools.exec.strictInlineEval = false;
cfg.tools.exec.security = 'allow';   // 最宽松，不触发 exec 级别安全门

fs.writeFileSync(process.env.HOME + '/.openclaw/openclaw.json', JSON.stringify(cfg, null, 2));
console.log('Patched:');
console.log('  tools.profile:', cfg.tools.profile);
console.log('  tools.exec.strictInlineEval:', cfg.tools.exec.strictInlineEval);
console.log('  tools.exec.security:', cfg.tools.exec.security);
"

node -e "
