cfg.tools.exec.security = 'allowlist'; // allowlist = 最宽松白名单模式

fs.writeFileSync(process.env.HOME + '/.openclaw/openclaw.json', JSON.stringify(cfg, null, 2));
console.log('Fixed:');
console.log('  tools.profile:', cfg.tools.profile, '(valid: minimal/coding/messaging/full)');
console.log('  tools.exec.security:', cfg.tools.exec.security, '(valid: deny/allowlist/full)');
"

# 获取 npm 上各版本的发布时间和说明
for v in 2026.3.29 2026.3.30 2026.3.31 2026.3.31-beta.1; do
  info=$(npm show openclaw@${v} --json 2>/dev/null)
  if [ -n "$info" ]; then
    echo "=== $v ==="
    echo "$info" | node -e "const d=JSON.parse(require('fs').readFileSync('/dev/stdin','utf8')); console.log('date:', d.time?.created || d.time || 'N/A'); console.log('description:', d.description || 'N/A')" 2>/dev/null
  fi
done

# 也尝试从 GitHub 获取 changelog
echo ""
echo "=== GitHub Changelog ==="
curl -s "https://api.github.com/repos/openclaw/openclaw/releases?per_page=10" 2>/dev/null | node -e "
const r = JSON.parse(require('fs').readFileSync('/dev/stdin','utf8'));
r.forEach(rel => {
