const cfg = JSON.parse(require('fs').readFileSync('/dev/stdin','utf8'));
const tools = cfg.tools || {};
const gateway = cfg.gateway || {};
const channels = cfg.channels || {};
const agents = cfg.agents || {};
const commands = cfg.commands || {};
const logging = cfg.logging || {};

console.log('=== tools ===');
console.log('profile:', tools.profile);
console.log('exec.ask:', tools.exec?.ask);
console.log('exec.strictInlineEval:', tools.exec?.strictInlineEval);
console.log('exec.security:', tools.exec?.security);
console.log('elevated:', JSON.stringify(tools.elevated));
console.log('promptPermission:', tools.promptPermission);

console.log('\n=== gateway ===');
console.log('blackStreamingDefault:', gateway.blackStreamingDefault);
console.log('gateway.execApproval:', gateway.execApproval);
console.log('gateway.security:', gateway.security);

console.log('\n=== commands ===');
console.log(JSON.stringify(commands, null, 2));

console.log('\n=== channels ===');
Object.keys(channels).forEach(k => {
  const c = channels[k];
  if (c.allowFrom) console.log(k+'.allowFrom:', JSON.stringify(c.allowFrom));
  if (c.security) console.log(k+'.security:', JSON.stringify(c.security));
});

console.log('\n=== agents ===');
const main = (agents.list||[]).find(a=>a.id==='main') || {};
console.log('main tools.allow:', JSON.stringify(main.tools?.allow));
console.log('main tools.deny:', JSON.stringify(main.tools?.deny));
